describe("parseToolResult", () => {
  it("prefers structuredContent over the Markdown content block", () => {
    // A tool that renders Markdown for chat still exposes JSON for the client.
    const result = {
      content: [{ type: "text", text: "| Nodes | 2 |" }],
      structuredContent: { nodes: 2, active_edges: 5 },
    };
    expect(parseToolResult(result)).toEqual({ nodes: 2, active_edges: 5 });
  });

  it("parses JSON from the first text content block", () => {
    const result = { content: [{ type: "text", text: '{"nodes":2}' }] };
    expect(parseToolResult(result)).toEqual({ nodes: 2 });
  });

  it("returns the raw text when it is not JSON", () => {
    const result = { content: [{ type: "text", text: "not json" }] };
    expect(parseToolResult(result)).toBe("not json");
  });

  it("returns the whole result when there is no text block", () => {
    const result = { content: [] };
    expect(parseToolResult(result)).toBe(result);
  });
});

describe("resolveServerPath", () => {
  it("honours an explicit non-default configured path", () => {
    expect(resolveServerPath("/custom/mindleak-mcp", "/ws", { exists: () => true })).toBe(
      "/custom/mindleak-mcp"
    );
  });

  it("prefers a packaged server over a workspace build", () => {
    const resolved = resolveServerPath("mindleak-mcp", "/ws", {
      extensionPath: "/extension",
      platform: "linux",
      exists: (candidate) =>
        candidate === path.join("/extension", "bin", "mindleak-mcp") ||
        candidate === path.join("/ws", "target", "release", "mindleak-mcp"),
    });

    expect(resolved).toBe(path.join("/extension", "bin", "mindleak-mcp"));
  });

  it("uses a workspace build when the packaged server is absent", () => {
    const resolved = resolveServerPath("mindleak-mcp", "/ws", {
      extensionPath: "/extension",
      platform: "linux",
      exists: (candidate) => candidate === path.join("/ws", "target", "release", "mindleak-mcp"),
    });

    expect(resolved).toBe(path.join("/ws", "target", "release", "mindleak-mcp"));
  });

  it("prefers a release build when it exists (win32)", () => {
    const resolved = resolveServerPath("mindleak-mcp", "C:/ws", {
      platform: "win32",
      exists: (p) => p.includes("release"),
    });
    expect(resolved).toContain("release");
    expect(resolved).toContain("mindleak-mcp.exe");
  });

  it("falls back to debug when release is absent", () => {
    const resolved = resolveServerPath("mindleak-mcp", "/ws", {
      platform: "linux",
      exists: (p) => p.includes("debug"),
    });
    expect(resolved).toContain("debug");
    expect(resolved.endsWith("mindleak-mcp")).toBe(true);
  });

  it("falls back to the bare command when no build is found", () => {
    expect(resolveServerPath("mindleak-mcp", "/ws", { exists: () => false })).toBe("mindleak-mcp");
  });
});

