describe("telemetryDashboard", () => {
  it("derives success/error rates, weighted latency, and sorted tool rows", () => {
    const dashboard = telemetryDashboard(SNAPSHOT, { nodes: 42, active_edges: 17 });
    expect(dashboard.nodes).toBe(42);
    expect(dashboard.activeEdges).toBe(17);
    expect(dashboard.totalEvents).toBe(10);
    expect(dashboard.totalErrors).toBe(2);
    expect(dashboard.successRatePct).toBe(80);
    expect(dashboard.errorRatePct).toBe(20);
    // weighted: (300 + 40) / (6 + 4) = 34
    expect(dashboard.avgLatencyMs).toBe(34);
    expect(dashboard.tools.map((t) => t.name)).toEqual(["recall", "graph_stats"]);
    expect(dashboard.tools[0]).toMatchObject({
      calls: 6,
      errors: 2,
      errorRatePct: 33.3,
      avgMs: 50,
      currentlyFailing: true,
    });
  });

  it("reports live failing-tool health distinct from the lifetime error tally", () => {
    // Regression: a tool with a resolved historical error (lifetime errors = 1)
    // whose most recent call succeeded must read as healthy — not an active
    // fault. failingTools is the live signal; totalErrors stays cumulative.
    const snapshot: TelemetrySnapshot = {
      total_events: 3,
      total_errors: 1,
      currently_failing_tools: 0,
      by_name: [
        {
          name: "recall",
          calls: 2,
          errors: 1,
          total_ms: 30,
          min_ms: 10,
          max_ms: 20,
          avg_ms: 15,
          last_error_at: 100,
          last_success_at: 200,
          last_error_detail: { error: "transient boom" },
          currently_failing: false,
        },
      ],
      recent: [],
    };
    const dashboard = telemetryDashboard(snapshot, { nodes: 1, active_edges: 0 });
    expect(dashboard.totalErrors).toBe(1);
    expect(dashboard.failingTools).toBe(0);
    expect(dashboard.tools[0].currentlyFailing).toBe(false);
  });

  it("flags a tool as failing when its latest call errored", () => {
    const snapshot: TelemetrySnapshot = {
      total_events: 2,
      total_errors: 1,
      currently_failing_tools: 1,
      by_name: [
        {
          name: "embed",
          calls: 2,
          errors: 1,
          total_ms: 14,
          min_ms: 5,
          max_ms: 9,
          avg_ms: 7,
          last_error_at: 200,
          last_success_at: 100,
          currently_failing: true,
        },
      ],
      recent: [],
    };
    const dashboard = telemetryDashboard(snapshot, undefined);
    expect(dashboard.failingTools).toBe(1);
    expect(dashboard.tools[0].currentlyFailing).toBe(true);
  });

  it("reports a clean 100% success readout when nothing has run yet", () => {
    const dashboard = telemetryDashboard(undefined, undefined);
    expect(dashboard).toMatchObject({
      nodes: 0,
      activeEdges: 0,
      totalEvents: 0,
      totalErrors: 0,
      failingTools: 0,
      successRatePct: 100,
      errorRatePct: 0,
      avgLatencyMs: 0,
      tools: [],
    });
  });
});

describe("formatLogLine", () => {
  it("renders a deterministic UTC line with outcome, kind:name, and duration", () => {
    expect(
      formatLogLine({
        ts: 1_700_000_000,
        kind: "tool_call",
        name: "recall",
        outcome: "ok",
        duration_ms: 12,
      })
    ).toBe("22:13:20 ok tool_call:recall 12ms");
  });

  it("omits duration when it is absent", () => {
    expect(
      formatLogLine({ ts: 1_700_000_000, kind: "maintenance", name: "prune", outcome: "ok" })
    ).toBe("22:13:20 ok maintenance:prune");
  });
});

describe("logLines", () => {
  it("returns newest-first formatted lines when live", () => {
    expect(logLines(SNAPSHOT, true)).toEqual([
      "22:13:25 error tool_call:recall 90ms",
      "22:13:20 ok tool_call:graph_stats 5ms",
    ]);
  });

  it("returns nothing when live logging is off", () => {
    expect(logLines(SNAPSHOT, false)).toEqual([]);
  });

  it("caps the number of lines", () => {
    expect(logLines(SNAPSHOT, true, 1)).toEqual(["22:13:25 error tool_call:recall 90ms"]);
  });
});
